#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;
my $next = $cgi->param('next') || '';

my $redirect_url = '/';

if ($next) {
    $next =~ s/^\s+|\s+$//g;
    
    if ($next =~ /^https?:\/\//) {
        my $server_name = $ENV{'SERVER_NAME'} || '';
        my $http_host = $ENV{'HTTP_HOST'} || '';
        
        if ($next =~ /^https?:\/\/(?:\Q$server_name\E|\Q$http_host\E)\//) {
            $redirect_url = $next;
        }
    } elsif ($next =~ /^\/[^\/]/) {
        $redirect_url = $next;
    }
}

print "Location: $redirect_url\n\n";